# Extended shapes with concrete implementations and enums
from shapes import Shape, Point

enum Color:
    RED = 0
    GREEN = 1
    BLUE = 2

class Rectangle(Shape):
    width: float
    height: float
    color: Color

    def __init__(self, name: str, w: float, h: float, c: Color):
        super().__init__(name)
        self.width = w
        self.height = h
        self.color = c

    def compute_area(self) -> float:
        return self.width * self.height

    def compute_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float
    center: Point

    def __init__(self, name: str, x: float, y: float, r: float):
        super().__init__(name)
        self.center = Point(x, y)
        self.radius = r

    def compute_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def compute_perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"Circle({self.name}) at ({self.center.x}, {self.center.y})"

