# Utility functions and generic containers for shapes
from shapes import Shape
from shapes_extended import Rectangle, Circle, Color

class ShapeCollection[T: Shape]:
    items: list[T]

    def __init__(self):
        self.items = []

    def add(self, item: T):
        self.items.append(item)

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self.items:
            total = total + shape.compute_area()
        return total

def classify_color(c: Color) -> str:
    if c == Color.RED:
        return "warm"
    else:
        return "cool"

def compare_shapes(a: Shape, b: Shape) -> bool:
    return a.compute_area() > b.compute_area()
